 /// <summary>
 /// Provides web search and note-taking tools for the research agent.
 /// </summary>
 sealed class ResearchTools(IHttpClientFactory httpClientFactory, ILogger<ResearchTools> logger)
 {
     private readonly List<string> _notes = [];

     [Description("Search the web for information on a query. Returns a list of result titles, URLs, and snippets.")]
     public async Task<string> SearchWeb(
         [Description("The search query string")] string query,
         CancellationToken cancellationToken = default)
     {
         logger.LogDebug("Searching web for: {QueryLength} chars", query.Length);

         using var client = httpClientFactory.CreateClient();
         client.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

         try
         {
             // DuckDuckGo Instant Answer API — no API key required
             var encodedQuery = Uri.EscapeDataString(query);
             var url = $"https://api.duckduckgo.com/?q={encodedQuery}&format=json&no_html=1";

             var response = await client.GetFromJsonAsync<JsonElement>(url, cancellationToken);
             var results = new List<string>();

             var abstractText = response.GetProperty("AbstractText").GetString();
             var abstractSource = response.GetProperty("AbstractSource").GetString();
             var abstractUrl = response.GetProperty("AbstractURL").GetString();

             if (!string.IsNullOrWhiteSpace(abstractText))
             {
                 results.Add($"[{abstractSource}] {abstractText}\nURL: {abstractUrl}");
             }

             if (response.TryGetProperty("RelatedTopics", out var topics))
             {
                 foreach (var relatedTopic in topics.EnumerateArray().Take(5))
                 {
                     if (relatedTopic.TryGetProperty("Text", out var text) &&
                         relatedTopic.TryGetProperty("FirstURL", out var topicUrl))
                     {
                         results.Add($"- {text.GetString()}\n  URL: {topicUrl.GetString()}");
                     }
                 }
             }

             if (results.Count == 0)
             {
                 return $"No results found for '{query}'. Try rephrasing your search.";
             }

             return string.Join("\n\n", results);
         }
         catch (Exception ex)
         {
             logger.LogWarning(ex, "Web search failed");
             return $"Search failed: {ex.Message}. Try a different query.";
         }
     }

     [Description("Save a research note. Use this to record key findings as you discover them.")]
     public string SaveNote(
         [Description("The note content to save")] string content,
         [Description("A short label or category for the note")] string label)
     {
         logger.LogDebug("Saving note with label: {Label}", label);
         _notes.Add($"[{label}] {content}");
         return $"Note saved ({_notes.Count} total). Label: {label}";
     }

     [Description("Retrieve all saved research notes.")]
     public string GetNotes()
     {
         if (_notes.Count == 0)
         {
             return "No notes saved yet.";
         }

         return $"=== {_notes.Count} Research Notes ===\n" + string.Join("\n\n", _notes);
     }
 }

 /// <summary>
 /// Orchestrates the research agent workflow using Microsoft Agent Framework.
 /// </summary>
 sealed class ResearchAgentRunner(
     IChatClient chatClient,
     ResearchTools tools,
     ILogger<ResearchAgentRunner> logger)
 {
     private const string SystemPrompt = """
         You are a research agent. Your job is to thoroughly research a topic using the tools available to you.

         Follow this process:
         1. Break the topic into 2-3 specific search queries
         2. Search the web for each query
         3. Save important findings as notes with descriptive labels
         4. After gathering enough information, retrieve your notes
         5. Provide a comprehensive summary with key findings and source URLs

         Always save at least 3 notes before writing your summary.
         Be thorough but concise in your final summary.
         """;

     public async Task ResearchAsync(string topic, CancellationToken cancellationToken = default)
     {
         Console.WriteLine($"\n🔍 Researching: {topic}\n");

         var aiTools = new List<AITool>
         {
             AIFunctionFactory.Create(tools.SearchWeb),
             AIFunctionFactory.Create(tools.SaveNote),
             AIFunctionFactory.Create(tools.GetNotes),
         };

         var agent = new ChatClientAgent(
             chatClient,
             instructions: SystemPrompt,
             name: "ResearchAgent",
             description: "An agent that researches topics by searching the web and taking notes",
             tools: aiTools);

         var prompt = $"Research the following topic and provide a detailed summary: {topic}";

         var runOptions = new ChatClientAgentRunOptions(new ChatOptions
         {
             Temperature = 0f,
             MaxOutputTokens = 2048,
         });

         try
         {
             var response = await agent.RunAsync(prompt, options: runOptions, cancellationToken: cancellationToken);

             Console.WriteLine("═══════════════════════════════════════");
             Console.WriteLine("  RESEARCH SUMMARY");
             Console.WriteLine("═══════════════════════════════════════\n");

             foreach (var message in response.Messages)
             {
                 if (message.Role == ChatRole.Assistant)
                 {
                     var text = message.Text;
                     if (!string.IsNullOrWhiteSpace(text))
                     {
                         Console.WriteLine(text);
                     }
                 }
             }

             Console.WriteLine("\n═══════════════════════════════════════");
         }
         catch (Exception ex)
         {
             logger.LogError(ex, "Research agent failed");
             Console.Error.WriteLine($"\n❌ Research failed: {ex.Message}");
         }
     }
 }

